/**
 * DOC-FLOW: Processar Webhook API
 * O que faz: Recebe o webhook do WhatsApp, valida evento e extrai telefone/texto/botao.
 * Para que serve: Iniciar o processamento da conversa e evitar mensagens duplicadas.
 */
/**
 * V7.10 - Processamento de Webhook do WhatsApp API
 * Responsável por receber, validar e encaminhar mensagens.
 */
node.warn('FLOW VERSION: V7.10');
const debugEnabled = flow.get('CHATBOT_DEBUG') === true;
if (debugEnabled) node.warn('V7.10 - webhook GET+roteamento+limpeza');

try {
  if (msg.req && msg.req.method === 'GET') {
    const q = (msg.req && msg.req.query) ? msg.req.query : {};
    msg.payload = q['hub.challenge'] || q.hub_challenge || 'OK';
    msg.statusCode = 200;
    return [msg, null];
  }

  const body = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};

  if (!body || body.object !== 'whatsapp_business_account') {
    msg.payload = 'OK';
    msg.statusCode = 200;
    return [msg, null];
  }

  const entries = Array.isArray(body.entry) ? body.entry : [];
  const now = Date.now();
  const previous = flow.get('processedMsgIds');
  const processedIds = Array.isArray(previous) ? previous : [];
  const cleanedIds = processedIds.filter(item => item && item.id && (now - Number(item.timestamp || 0)) < 7200000);

  let hasNewMessage = false;

  entries.forEach(entry => {
    const changes = Array.isArray(entry && entry.changes) ? entry.changes : [];
    changes.forEach(change => {
      const value = (change && change.value) ? change.value : {};
      const webhookPhoneNumberId = (value && value.metadata && value.metadata.phone_number_id) ? String(value.metadata.phone_number_id) : null;

      if (value.statuses) return;

      const messages = Array.isArray(value.messages) ? value.messages : [];
      messages.forEach(m => {
        if (!m || !m.from || !m.id) return;
        if (cleanedIds.some(item => item.id === m.id)) return;

        const button = (m.interactive && m.interactive.button_reply && m.interactive.button_reply.id)
          || (m.interactive && m.interactive.list_reply && m.interactive.list_reply.id)
          || null;
        const text = (m.text && m.text.body) ? m.text.body : null;
        const messageType = (m.type || '').toString().toLowerCase();
        const unsupportedTypes = new Set(['image', 'video', 'audio', 'document']);
        const unsupportedContent = unsupportedTypes.has(messageType);

        if (!text && !button && !unsupportedContent) return;

        cleanedIds.push({ id: m.id, timestamp: now });
        hasNewMessage = true;

        node.send([null, {
          payload: body,
          phone: m.from,
          text: text,
          button: button,
          type: m.type,
          phoneId: webhookPhoneNumberId,
          unsupportedContent: unsupportedContent,
          messageId: m.id
        }]);
      });
    });
  });

  flow.set('processedMsgIds', cleanedIds);

  if (!hasNewMessage) {
    // Sem mensagem nova: apenas ACK para o provedor.
  }

  msg.payload = 'OK';
  msg.statusCode = 200;
  return [msg, null];
} catch (err) {
  node.error('Erro no webhook: ' + (err && err.message ? err.message : err), msg);
  msg.payload = 'OK';
  msg.statusCode = 200;
  return [msg, null];
}

const phone = msg.phone;
const phoneId = msg.phoneId;

if (!phone || (!msg.text && !msg.button)) return null;
if(!phoneId) return null;

const contextKey = `ctx_api_${phone}_${phoneId}`;
let ctx = flow.get(contextKey) || { step: "LGPD", tentativas: 0, createdAt: Date.now() };

const now = Date.now();
const ttl = 30 * 60 * 1000;

// SE EXPIROU, RESETAR
if (ctx.updatedAt && (now - ctx.updatedAt > ttl)) {
    ctx = { step: "LGPD", tentativas: 0, createdAt: now };
}

ctx.updatedAt = now;
flow.set(contextKey, ctx);

msg.ctx = ctx;
msg.contextKey = contextKey;
msg.now = now;
msg.whatsappToken = ctx.whatsappToken ? ctx.whatsappToken : null;

node.warn(`${phone} -> ${ctx.step} | ${msg.text || msg.button}`);
return msg;

const ctx = msg.ctx;
const contextKey = msg.contextKey;

// SE JÁ ACEITOU LGPD, NÃO ENVIAR NOVAMENTE
if (ctx.lgpdAceita) {
    return null;
}
ctx.memoryId = null;
if (ctx.lgpdEnviada && msg.button === "LGPD_OK") {
    ctx.step = "Flow";
    ctx.lgpdAceita = true;
    ctx.lgpdEnviada = false;
    flow.set(contextKey, ctx);
    msg.reply = { type: "text", text: "Consentimento aceito!\nAgora podemos continuar com seu atendimento. Você pode consultar agendamentos, reagendar uma consulta, ou realizar um novo agendamento de consulta.\n\nComo posso te ajudar?"};
    return msg;
}

if (ctx.lgpdEnviada && msg.button === "LGPD_NOK") {
    ctx.encerrado = true;
    ctx.step = "LGPD";
    ctx.lgpdEnviada = false;
    ctx.updatedAt = msg.now;
    flow.set(contextKey, ctx);
    msg.reply = { type: "text", text: "Sem problemas 😊\nPorém, para seguir com o atendimento, precisamos do seu consentimento.\nAté mais! Se mudar de ideia, estarei aqui para continuar, é só dar um oi."};
    return msg;
}

// ENVIAR LGPD APENAS UMA VEZ
if (ctx.lgpdEnviada) {
    return null;
}

ctx.lgpdEnviada = true;
flow.set(contextKey, ctx);

msg.buscarTermoUso = true;
return msg;

const ctx = msg.ctx;
const contextKey = msg.contextKey;
const memoryId = ctx.memoryId || null;
const input = msg.text;
const wabaId = msg.payload?.entry[0]?.id || null;
const phone = msg.phone || 'null';
const todayDate = new Date();
node.warn(todayDate);

msg.inputPayload = msg.payload;
msg.payload = `## CONTEXT ##\ncontextKey = ${contextKey}\nwabaId = ${wabaId}\nphoneNumber = ${phone}\ntodayDate = ${todayDate}\n## INPUT ##\n${input}`;
msg.memoryId = memoryId;

return msg;

const TOKEN = msg.whatsappToken;
const PHONE_ID = msg.phoneId;

if (!msg.reply || !msg.phone || !msg.whatsappToken) return null;

msg.headers = { Authorization: `Bearer ${TOKEN}`, "Content-Type": "application/json" };
msg.url = `https://graph.facebook.com/v24.0/${PHONE_ID}/messages`;
msg.method = "POST";

let payload = { messaging_product: "whatsapp", recipient_type: "individual", to: msg.phone };

if (msg.reply.type === "interactive") {
    payload.type = "interactive";
    payload.interactive = {
        type: "button",
        body: { text: msg.reply.text },
        action: { buttons: msg.reply.buttons.slice(0, 3).map(b => ({ type: "reply", reply: { id: b.id, title: b.title.substring(0, 20) } })) }
    };
} else if (msg.reply.type === "list") {
    payload.type = "interactive";
    payload.interactive = {
        type: "list",
        body: { text: msg.reply.text },
        action: {
            button: msg.reply.buttonText || "Ver opções",
            sections: msg.reply.sections
        }
    };
} else {
    payload.type = "text";
    payload.text = { body: msg.reply.text, preview_url: false };
}

node.warn(`📤 Enviando ${payload.type} para ${msg.phone}`);
node.warn(`📦 Payload: ${JSON.stringify(payload).substring(0, 200)}...`);
msg.payload = payload;
return msg;

msg.reply = msg.payload.response || "Operação realizada com sucesso!\nO atendimento está sendo finalizado! Caso necessário, só mandar mensagem para iniciar um novo atendimento!";
const ctx = msg.ctx;

if(!ctx.memoryId) {
    ctx.memoryId = msg.payload?.info?.memoryId || null;
    flow.set(msg.contextKey, ctx);  
}

msg.reply = {
    type: "text",
    text: msg.payload?.response
}

msg.payload = msg.inputPayload;
return msg;

/**
 * DOC-FLOW: Controle de Taxa (Rate Limit)
 * O que faz: Controla a quantidade de mensagens por telefone em uma janela de tempo.
 * Para que serve: Proteger o fluxo contra spam e sobrecarga.
 */
const phone = msg.phone;
if (!phone) return null;

const now = Date.now();
const windowMs = 60000;
const maxCount = 20;

let limits = flow.get('rateLimit') || {};
let history = limits[phone] || [];

history = history.filter(ts => now - ts < windowMs);

if (history.length >= maxCount) {
 limits[phone] = history;
 flow.set('rateLimit', limits);
 return null;
}

history.push(now);
limits[phone] = history;
flow.set('rateLimit', limits);

return msg;

const now = Date.now();
const ttl = 30 * 60 * 1000;
const prefix = 'ctx_api_';

const keys = flow.keys();
let removidos = 0;
node.warn(keys);
keys.forEach(k => {
    if (!k.startsWith(prefix)) {
        node.warn(`${k} is not a context`);
        return;
    }
    const ctx = flow.get(k);
    if (!ctx) {
        return;
    }
    const ref = ctx.updatedAt || ctx.createdAt;
    if (!ref) {
        flow.set(k, null);
        removidos++;
        return;
    }
    if (now - ref > ttl) {
        flow.set(k, null);
        removidos++;
        return;
    }
    node.warn(`CTX_CLEANUP - ${k} mantido`)
});

if (removidos > 0) {
    node.warn(`CTX_CLEANUP removidos=${removidos}`);
}

return null;

const contextKey = msg?.payload?.contextKey;

if(!contextKey) {
    msg.statusCode = 400;
    node.warn("Context cleanup - Unable to retrieve contextKey.");
}

flow.set(contextKey, {...flow.get(contextKey), memoryId: null});
node.warn(`Context cleanup - ${contextKey} removed.`);
msg.statusCode = 200;
return msg;

msg._wa = { url: msg.url, method: msg.method, headers: msg.headers, payload: msg.payload };
msg._waRetry = msg._waRetry || 0;
return msg;

const maxRetries = 3;
const baseDelay = 1500;
const payloadStr = (typeof msg.payload === 'string') ? msg.payload : '';
const status = msg.statusCode;
const isError = (status && status >= 400) || payloadStr.toLowerCase().includes('fetch failed') || payloadStr.toLowerCase().includes('error while fetching access token');
if (!isError) return null;

msg._waRetry = (msg._waRetry || 0) + 1;
if (msg._waRetry > maxRetries || !msg._wa) {
    return null;
}

const delay = baseDelay * msg._waRetry;
node.warn('⚠️ WhatsApp API falhou, retry ' + msg._waRetry + '/' + maxRetries + ' em ' + delay + 'ms');
const retryMsg = Object.assign({}, msg, {
    url: msg._wa.url,
    method: msg._wa.method,
    headers: msg._wa.headers,
    payload: msg._wa.payload
});
setTimeout(() => node.send(retryMsg), delay);
return null;

const contextKey = msg.contextKey;
const ctx = flow.get(contextKey) || msg.ctx;
const response = msg.payload;

let rows = [];
if (Array.isArray(response)) {
    rows = response;
} else if (response && response.select && response.select[0] && response.select[0].resultSet) {
    rows = response.select[0].resultSet;
}

const row = rows && rows[0] ? rows[0] : null;
const conteudo = (row && (row.DS_CONTEUDO || row.ds_conteudo)) ? (row.DS_CONTEUDO || row.ds_conteudo).toString() : '';
const sequencia = row && (row.NR_SEQUENCIA || row.nr_sequencia) ? (row.NR_SEQUENCIA || row.nr_sequencia).toString() : null;

const cleanMeta = (m) => Object.assign({}, msg, m, { buscarTermoUso: undefined, payload: undefined, topic: undefined });

const sendLater = (m, delayMs) => {
    setTimeout(() => {
        node.send(cleanMeta(m));
    }, delayMs);
};

const boasVindas = '👋 Olá! Seja bem-vindo(a) à Clinica CMDK. Sou o assistente virtual e antes de continuar, precisamos do seu consentimento para tratar seus dados pessoais conforme a LGPD.';

if (!conteudo) {
    msg.reply = { type: 'text', text: boasVindas };
    sendLater({ reply: { type: 'interactive', text: 'Selecione uma opção:', buttons: [ { id: 'LGPD_OK', title: 'Aceito' }, { id: 'LGPD_NOK', title: 'Não aceito' } ] } }, 600);
    return msg;
}

ctx.termoUsoSequencia = sequencia;
ctx.termoUsoConteudo = conteudo;
ctx.updatedAt = msg.now;
flow.set(contextKey, ctx);

const textoTermo = conteudo.length > 4000 ? conteudo.substring(0, 4000) : conteudo;

const aceiteReply = {
    type: 'interactive',
    text: 'Selecione uma opção:',
    buttons: [
        { id: 'LGPD_OK', title: 'Aceito' },
        { id: 'LGPD_NOK', title: 'Não aceito' }
    ]
};

msg.reply = { type: 'text', text: boasVindas };

if (textoTermo.length > 1000) {
    const parte1 = textoTermo.substring(0, 1000);
    const parte2 = textoTermo.substring(1000);
    sendLater({ reply: { type: 'text', text: parte1 } }, 600);
    sendLater({ reply: { type: 'text', text: parte2 } }, 1200);
    sendLater({ reply: aceiteReply }, 1800);
    return msg;
}

sendLater({ reply: { type: 'text', text: textoTermo } }, 600);
sendLater({ reply: aceiteReply }, 1200);
return msg;

const pessoaRaw = msg.payload?.naturalPersonCode ? msg.payload?.naturalPersonCode : '';
const agendaRaw = msg.payload?.integratedScheduleId ? msg.payload?.integratedScheduleId?.toString() : '';
const contextKey = msg.payload?.contextKey;
const pessoa = pessoaRaw.replace(/\D/g, '').substring(0, 10);
const agenda = agendaRaw.replace(/\D/g, '');

if (!pessoa || !agenda || !contextKey) return null;
const context = flow.get(contextKey) || null;
if(!context) return null;

const mk = (t, d) => ({
    histPessoa: pessoa,
    histAgenda: agenda,
    histTipo: t,
    histDesc: d
});

const acaoAgendar = mk(3, 'Consulta reagendada com sucesso');
let acaoTermo = mk(4, 'Termo de privacidade aceito');

const termoSalvo = context.termoSalvo || false;
if(termoSalvo) {
    node.warn("Termo previamentes salvo. Salvando apenas histórico de agendamento.")
    return [acaoAgendar, null];
}
flow.set(contextKey, {...context, termoSalvo: true})
node.warn("Salvando histórico de agendamento e de aceite de termo.")
return [acaoAgendar, acaoTermo];

const pessoaRaw = msg.payload?.naturalPersonCode ? msg.payload?.naturalPersonCode : '';
const agendaRaw = msg.payload?.integratedScheduleId ? msg.payload?.integratedScheduleId?.toString() : '';
const contextKey = msg.payload?.contextKey;
node.warn(pessoaRaw, agendaRaw);
const pessoa = pessoaRaw.replace(/\D/g, '').substring(0, 10);
const agenda = agendaRaw.replace(/\D/g, '');


if (!pessoa || !agenda || !contextKey) return null;
const context = flow.get(contextKey) || null;
if(!context) return null;

const mk = (t, d) => ({
    histPessoa: pessoa,
    histAgenda: agenda,
    histTipo: t,
    histDesc: d
});

const acaoAgendar = mk(1, 'Consulta agendada com sucesso');
let acaoTermo = mk(4, 'Termo de privacidade aceito');

const termoSalvo = context.termoSalvo || false;
if(termoSalvo) {
    node.warn("Termo previamentes salvo. Salvando apenas histórico de agendamento.")
    return [acaoAgendar, null];
}
flow.set(contextKey, {...context, termoSalvo: true})
node.warn("Salvando histórico de agendamento e de aceite de termo.")
return [acaoAgendar, acaoTermo];

const pessoaRaw = msg.payload?.naturalPersonCode ? msg.payload?.naturalPersonCode : '';
const agendaRaw = msg.payload?.integratedScheduleId ? msg.payload?.integratedScheduleId?.toString() : '';
const contextKey = msg.payload?.contextKey;
const pessoa = pessoaRaw.replace(/\D/g, '').substring(0, 10);
const agenda = agendaRaw.replace(/\D/g, '');

if (!pessoa || !agenda || !contextKey) return null;
const context = flow.get(contextKey) || null;
if(!context) return null;

const mk = (t, d) => ({
    histPessoa: pessoa,
    histAgenda: agenda,
    histTipo: t,
    histDesc: d
});

const acaoAgendar = mk(2, 'Consulta cancelada com sucesso');
let acaoTermo = mk(4, 'Termo de privacidade aceito');

const termoSalvo = context.termoSalvo || false;
if(termoSalvo) {
    node.warn("Termo previamentes salvo. Salvando apenas histórico de agendamento.")
    return [acaoAgendar, null];
}
flow.set(contextKey, {...context, termoSalvo: true})
node.warn("Salvando histórico de agendamento e de aceite de termo.")
return [acaoAgendar, acaoTermo];

const access_token = msg.payload?.select[0]?.resultSet[0]?.ACCESS_TOKEN || null
const contextKey = msg.contextKey;

if(!access_token) return null; // PARA O FLUXO (DA PARA TRATAR ERRO AQUI DEPOIS)
if(!contextKey) return null;

msg.whatsappToken = access_token;
flow.set(contextKey, {...flow.get(contextKey), whatsappToken: access_token})
return msg;

const TOKEN = msg.whatsappToken;
const PHONE_ID = msg.phoneId;

if (!msg.phone || !msg.whatsappToken) return null;

msg.headers = { Authorization: `Bearer ${TOKEN}`, "Content-Type": "application/json" };
msg.url = `https://graph.facebook.com/v24.0/${PHONE_ID}/messages`;
msg.method = "POST";

const entry = msg.payload?.entry[0];
if(!entry) return null;

const changes = entry.changes[0];
if(!changes) return null;

const message = changes.value?.messages[0];
if(!message) return null;

const messageId = message.id || null;
if(!messageId) return null;

msg.payload = {
  "messaging_product": "whatsapp",
  "status": "read",
  "message_id": messageId,
  "typing_indicator": {
    "type": "text"
  }
}

return msg;

const access_token = msg.payload?.select[0]?.resultSet[0]?.ACCESS_TOKEN || null
const contextKey = msg.contextKey;

if(!access_token) return null; // PARA O FLUXO (DA PARA TRATAR ERRO AQUI DEPOIS)
if(!contextKey) return null;

msg.whatsappToken = access_token;
flow.set(contextKey, {...flow.get(contextKey), whatsappToken: access_token})
return msg;
